// UTILITY: Cache Write v1.0.0
// Reusable utility called by any agent to write to Redis cache.
// INPUT:  { cache_key: string, data: any, ttl_seconds: number }
// OUTPUT: { written: boolean, cache_key: string, ttl_seconds: number }
//
// PLACEHOLDER: Logs the write intent but does nothing.
// In Phase 4, this will call Redis SETEX via n8n Redis node.

const input = $input.first().json;
const { cache_key, data, ttl_seconds = 3600 } = input;

if (!cache_key) throw new Error('[util_cache_write] Missing required field: cache_key');
if (data === undefined) throw new Error('[util_cache_write] Missing required field: data');

console.log(`[util_cache_write] KEY=${cache_key} TTL=${ttl_seconds}s → WRITE (placeholder, not persisted)`);

return [{
  json: {
    written:     false,
    cache_key,
    ttl_seconds,
    source:      'placeholder'
  }
}];
